"""
MKT Context Commentary — Genesis chapters 25–26
Run: python3 scripts/zc-context-genesis-25-26.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/translation/glossary-hebrew.json (key terms: bĕḵōrāh, bāzāh, ʿāqaḇ, mōrat rûaḥ)

Key decisions:
- Ch25: Keturah discussed as secondary wife vs. concubine per ANE customary law (Hammurabi §170-171)
- Ch25: "Gathered to his people" treated as patriarchal afterlife/ancestor-reunion idiom
- Ch25: Birthright sale analyzed as ANE oral contract with sworn witness
- Ch26: "Philistines" in Gerar treated as pre-Philistine Aegean coastal group, not the 12th-century Sea Peoples
- Ch26: Well-naming sequence (Esek/Sitnah/Rehoboth) interpreted as territorial-conflict resolution pattern
- Ch26: Abimelech's covenant-making read in light of ANE patron-witness treaty customs
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_CONTEXT = {
  "25": {
    "1": """<p>"Abraham had taken another wife, whose name was Keturah." The remarriage after Sarah's death raises an ANE legal question: what is Keturah's status? 1 Chr 1:32 calls her a <em>pîlegeš</em> (concubine), while the Hebrew here uses <em>ʾiššāh</em> (wife/woman). The distinction matters for inheritance: a wife's sons inherit; a concubine's sons receive gifts at best (v6). Abraham's continued fertility into old age (he would have been ~140 at this point if she bore his last son before he died at 175) is sometimes read as a parallel to Isaac's miraculous birth — a sign of ongoing divine vitality, though the covenant heir is already established as Isaac.</p>""",
    "2": """<p>Keturah's six sons — Zimran, Jokshan, Medan, <em>Midian</em>, Ishbak, Shuah — are the ancestral eponyms of Arabian/desert peoples. <em>Midian</em> will be the most significant in later biblical history: Moses flees to Midian (Exod 2:15), marries Zipporah the Midianite, and receives his priestly formation from Jethro. Midianite traders appear in the Joseph story (37:28,36). The Midianites later become Israel's enemies in the time of Gideon (Judg 6-8). This verse establishes that Abraham is the ancestor of peoples with whom Israel will have complex relationships across centuries.</p>""",
    "3": """<p>Sheba and Dedan are the sons of Jokshan; Sheba is likely the Arabian kingdom of the Queen of Sheba who visits Solomon (1 Kgs 10:1-13). Dedan is a well-attested Arabian trading city in northwestern Arabia (Ezek 25:13; 27:15,20; Isa 21:13). The descendants of Dedan — the Ashurites, Letushites, and Leummites — are otherwise unknown from extrabiblical sources; they were probably nomadic clan-groups whose identities were absorbed into larger tribal formations. The placement of Sheba and Dedan here (as descendants of Keturah through Jokshan) coexists with another Sheba/Dedan genealogy in Gen 10:7 (descendants of Ham through Cush and Raamah) — reflecting the fluidity of ANE genealogical traditions for shared-territory peoples.</p>""",
    "4": """<p>"The sons of Midian" — five sub-clans. <em>Ephah</em> appears in Isa 60:6 as a Midianite clan bringing gold and incense to Jerusalem. <em>Hanok</em> is the same name as Enoch (Ḥănôk), a shared Semitic personal name. The five sub-clans of Midian structure the genealogy in parallel to the twelve tribal units of Israel: Abraham's non-covenant lines also develop internal genealogical organization. The summary "all these were descendants of Keturah" closes the secondary-wife genealogy and marks these peoples as related to but distinct from the covenant-line — sharing Abrahamic ancestry but not Abrahamic covenant-election.</p>""",
    "5": """<p>"Abraham left everything he owned to Isaac" — this is the inheritance declaration. <em>Kol ʾăšer-lô</em> (everything he had) is the comprehensive formula. The legal arrangement follows the ANE convention for a primary heir: the firstborn-of-the-primary-wife received the full inheritance. Though Isaac was not Abraham's biological firstborn (Ishmael was born first), YHWH's election of Isaac as covenant-heir (17:19-21; 21:12) and the removal of Ishmael from the household (21:14) established Isaac's uncontested legal inheritance position. The formal statement here serves as the testament before the narrative of the secondary-sons' settlement (v6).</p>""",
    "6": """<p>"He gave gifts to the sons of his concubines and sent them away... to the land of the east." The word here for "concubines" is <em>pîlagšîm</em> (plural of <em>pîlegeš</em>) — the same status 1 Chr 1:32 assigns Keturah. The gift-versus-inheritance distinction is legally significant: the Code of Hammurabi (§170-171) addresses the sons of a secondary wife: if acknowledged, they share inheritance; if given gifts and sent away, they forfeit inheritance claims. Abraham's arrangement — gifts plus geographic separation — removes the secondary sons from the inheritance zone and preempts future legal conflict with Isaac. "The land of the east" (<em>ʾereṣ qeḏem</em>) is the general term for Arabia and the Syrian desert, the territory of the pastoral/nomadic peoples descended from these sons.</p>""",
    "7": """<p>"Abraham lived a hundred and seventy-five years." The patriarchal life-spans in Genesis are decreasing from Adam's 930 (ch5) through Noah's 950 (9:29), Shem's 600 (11:10), and Abraham's 175 — the trajectory toward normal human life-span. In ANE cultural context, long life was a sign of divine blessing and wisdom; the patriarchs' extreme ages mark them as figures of an earlier, more-blessed era. Abraham's 175 years place his death chronologically when Isaac is 75 and Jacob and Esau are 15 (since Isaac married at 40 and the twins were born 20 years later at v26: Isaac was 60).</p>""",
    "8": """<p>"Breathed his last and died at a good old age, an old man full of years; and he was gathered to his people." Three parallel phrases mark Abraham's death as complete and honorable: (1) <em>wayyigwaʿ</em> (breathed his last — the same verb for animal death: Num 20:29; used for patriarchal deaths in a formulaic sense), (2) <em>śĕḇaʿ yāmîm</em> (full of days/years — the idiom of a sated, complete life: Job 42:17; 1 Chr 29:28), and (3) <em>wayyēʾāsep ʾel-ʿammāyw</em> (was gathered to his people). The last phrase implies reunion with deceased ancestors — a concept of post-mortem communal identity that is distinct from later Sheol theology. The gathered-to-people formula presupposes that the "people" to whom one is gathered exist and are accessible, suggesting that Abraham expected a continued existence after death among his ancestors.</p>""",
    "9": """<p>"His sons Isaac and Ishmael buried him in the cave of Machpelah." The joint burial of Abraham by the two rival brothers is significant: despite their separation (ch21), both sons return for their father's burial. In ANE culture, burial of a parent was a sacred obligation that superseded family conflict (the Egyptian Instructions of Ani; the Akkadian advice literature). The cave of Machpelah had been purchased by Abraham for Sarah's burial at a precise legal price (400 shekels, ch23) — it was now Abraham's established family tomb. Mamre was his settled home-base in Canaan. The presence of Ishmael at the burial is the last recorded act of the Ishmael narrative; he and Isaac will next appear only in their own genealogical closings.</p>""",
    "10": """<p>"The field Abraham had bought from the Hittites. There Abraham was buried with his wife Sarah." The double restatement of the Machpelah purchase and the joint burial of Abraham with Sarah is the legal record: the deed of purchase (ch23) established ownership; the burials establish the tomb's identity as the patriarchal family grave. The Machpelah cave at Hebron will become the burial site for Isaac and Rebekah (35:27-29) and Leah (49:31) as well; Jacob requests and receives burial there (49:30; 50:12-13). The family tomb at Machpelah is the physical anchor of the covenant family's claim to Canaan — a purchased, witnessed, legally undeniable deed in the land of promise.</p>""",
    "11": """<p>"After Abraham's death, God blessed his son Isaac, who then lived near Beer Lahai Roi." The covenant's transfer to Isaac is stated with brevity — YHWH blessed Isaac — but the single statement is the narrative's most important transition: the Abrahamic covenant now passes to the second generation. "Beer Lahai Roi" (<em>bĕʾēr laḥay rōʾî</em>, the well of the Living One who sees me) is the place of Hagar's angel encounter (16:14) and where Isaac was living when Rebekah arrived from Paddan-Aram (24:62). Isaac's life at Hagar's sacred well creates a subtle narrative link between the two branches of Abraham's family — Isaac lives at the place sacred to Ishmael's mother.</p>""",
    "12": """<p>"This is the account (<em>toledot</em>) of the family line of Abraham's son Ishmael." The second toledot formula in ch25 (after the Abraham-toledot that opened this chapter in the wider narrative structure). The toledot formula appears ten times in Genesis as a literary structural marker; this is the toledot of Ishmael — a formal closing of one narrative thread before opening the main thread (Isaac's toledot follows in v19). The identification of Ishmael's mother as "Sarah's slave, Hagar the Egyptian" — with both the slave-status and ethnic identity — frames the Ishmael genealogy within the complicated social hierarchy of the previous narrative: Ishmael was born of a slave woman, which determined his inheritance status.</p>""",
    "13": """<p>"Listed in the order of their birth: Nebaioth the firstborn of Ishmael" — the birth-order listing signals a formal genealogical record. <em>Nebaioth</em> is identified in later sources with the Nabataeans, the Arabian people who built Petra (in modern Jordan) and controlled the incense trade routes. <em>Kedar</em> is the most prominent Ishmaelite tribe in later OT prophecy (Isa 21:16-17; 42:11; 60:7; Jer 2:10; 49:28-29; Ps 120:5) — an Arab pastoral people of the Syrian desert known for their black tents. The Kedarites are the ANE trade and military force in the Arabian world. The twelve sons of Ishmael structurally parallel the twelve sons of Jacob — an intentional literary parallel suggesting that Ishmael's line also has a complete tribal structure, though outside the covenant.</p>""",
    "14": """<p>Mishma, Dumah, Massa — three more Ishmaelite son-names. <em>Dumah</em> appears in Isa 21:11 as an Arabian place-name ("the oracle concerning Dumah" — likely the oasis of Dumat al-Jandal in northwestern Arabia). <em>Massa</em> appears in Prov 30:1 and 31:1 as the tribe of the sages Agur and Lemuel — suggesting a wisdom tradition in the Ishmaelite tribal world that intersects with Israelite wisdom literature. The tribal genealogy thus identifies peoples who will appear in later biblical narrative at various points of intersection with Israel.</p>""",
    "15": """<p>Hadad, Tema, Jetur, Naphish, and Kedemah. <em>Tema</em> is an important Arabian oasis city (modern Tayma in northwestern Arabia) mentioned in Isa 21:14 and Job 6:19 — a major caravan hub. <em>Jetur</em> and <em>Naphish</em> appear in 1 Chr 5:19 as peoples against whom the Reubenites and Gadites fought east of the Jordan — confirming the Ishmaelite tribes' range into Transjordan and northern Arabia. <em>Kedemah</em> means "eastward/eastern" — possibly a geographic-direction eponym for the easternmost Ishmaelite settlements.</p>""",
    "16": """<p>"Twelve tribal rulers (<em>nĕśîʾîm</em>) according to their settlements and camps." The twelve-ruler structure of Ishmael's line precisely mirrors the twelve tribes of Jacob/Israel. The word <em>nāśîʾ</em> (ruler, prince, one who is lifted up) is the term used for tribal chiefs in Israel's wilderness period (Num 1:16; 7:2). Both "settlements" (<em>ḥaṣerêhem</em>, encampments/villages) and "camps" (<em>ṭirōtām</em>, enclosures/camps) reflect the semi-nomadic lifestyle of the Ishmaelite tribes — moving between settled locations and nomadic camping grounds seasonally. The parallel twelve-unit structure is a structural statement: YHWH's promise to Ishmael (17:20: "I will make him into a great nation") has been fulfilled with the same formal organization as the covenant people.</p>""",
    "17": """<p>"Ishmael lived a hundred and thirty-seven years. He breathed his last and died, and he was gathered to his people." Ishmael's death notice uses the same <em>wayyigwaʿ</em> (breathed his last) and <em>wayyēʾāsep ʾel-ʿammāyw</em> (gathered to his people) formulas as Abraham's death (v8). The parallel formula is not accidental: Ishmael, though outside the covenant-election, receives an honorable death notice in the same formal language as his father. His 137 years place him within the decreasing life-span trajectory of the post-Flood patriarchs, shorter than his father Abraham's 175 but longer than his half-brother Isaac's 180 years (35:28).</p>""",
    "18": """<p>"From Havilah to Shur, near the eastern border of Egypt." The geographic range describes the Arabian Peninsula and Sinai region. Havilah appears in Gen 2:11 as a land of gold; here it marks the eastern edge of the Ishmaelite territorial range. Shur is in the Sinai, the desert wilderness between Egypt and Canaan (where Hagar fled in 16:7). "As you go toward Ashur" (<em>ʿal-pĕnê ʾaššûr</em>, before/in front of Assyria) — the directional landmark locates the territory relative to Assyria to the northeast. "Lived in hostility toward all his brothers" — the word <em>nāpal</em> (fell) is sometimes rendered "settled" (the NASB) but the idiom <em>ʿal-pĕnê</em> (over against / in the face of) combined with <em>ʾaḥāyw</em> (his brothers) echoes 16:12's oracle: Ishmael will "live over against all his brothers" — fulfilling the angel's word to Hagar.</p>""",
    "19": """<p>"This is the account (<em>toledot</em>) of the family line of Abraham's son Isaac." The ninth toledot formula in Genesis introduces the main narrative thread that will run through the end of the book. The repetition "Abraham was the father of Isaac" after the Ishmael-toledot (which closed Ishmael's line) formally hands the narrative torch from the Ishmael-thread to the Isaac-thread. The double identification — "Abraham's son Isaac" and "Abraham became the father of Isaac" — emphasizes the covenant's continuity through the specific father-son chain YHWH established.</p>""",
    "20": """<p>"Isaac was forty years old when he married Rebekah daughter of Bethuel the Aramean from Paddan Aram." The marriage at 40 and the 20-year gap before the twins' birth (Isaac was 60 at their birth, v26) structures the barrenness theme. "Paddan Aram" (<em>paddān ʾărām</em>, the plain of Aram) is the region around Harran in northern Mesopotamia (modern southeastern Turkey/northern Syria) — the same region where Laban lived (28:2-7) and where Jacob will spend 20 years (29-31). The twice-repeated "the Aramean" for both Bethuel and Laban establishes the Aramean identity of the covenant-family's maternal line — important because Jacob's sons will also be half-Aramean, and the confession "my father was a wandering Aramean" (Deut 26:5) will summarize the covenant-family's ethnic origins.</p>""",
    "21": """<p>"Isaac prayed to the LORD on behalf of his wife, because she was childless." Rebekah's barrenness follows the same pattern as Sarah's (11:30) — the covenant heir's birth is a divine gift, not human biological productivity. The verb <em>wayyeʿtar</em> (he prayed/entreated) may derive from a root meaning "to burn incense" (offering a petitionary prayer at an altar) or simply "to pray urgently." The twenty years of barrenness before YHWH "answered" (<em>wayyēʿāter</em>, the same verb root in passive/reflexive) show that Isaac's prayer was sustained over a long period, not a quick request. The contrast with Abraham and Sarah's situation: Abraham's solution was to use Hagar (ch16); Isaac prays and waits, a more direct covenant-trust model.</p>""",
    "22": """<p>"The babies jostled each other within her." The word <em>wayyitroṣeṣû</em> (they were struggling/crushing) describes intense fetal movement — more than normal; the intensity prompted Rebekah's theological question. "She went to inquire of the LORD" (<em>liḏrōš ʾet-YHWH</em>) — the technical term <em>dāraš</em> (to seek, inquire) is the vocabulary of oracle-seeking at a sanctuary. This is the first use of this technical formula for a woman seeking a divine oracle directly. Where she went is not specified — perhaps a local altar, a sacred site, or through a prophetic intermediary. Her question "Why is this happening to me?" (<em>lāmmāh zeh ʾānōkî</em>, "why do I exist?" — literally "why is this, I?") expresses existential bewilderment at the painful pregnancy.</p>""",
    "23": """<p>"Two nations are in your womb, and two peoples from within you will be separated." The oracle is structured in four parallel lines: (1) two nations (<em>gôyim</em>), (2) two peoples (<em>leʾummîm</em>), (3) one stronger than the other, (4) the older serving the younger. The word <em>leʾummîm</em> (peoples, communities) is a poetic word for ethnic groups. The oracle does not name Jacob or Esau specifically — it addresses Rebekah as the mother of these two groups. The "older serving the younger" reversal anticipates the repeated younger-over-older pattern in Genesis (Isaac over Ishmael; Jacob over Esau; Ephraim over Manasseh) and gives it divine sanction from the womb. Paul cites this oracle in Romans 9:10-13 as a demonstration of divine election operating before birth and independent of human action.</p>""",
    "24": """<p>"There were twin boys in her womb." The twin birth in the OT is significant: twins appear in Gen 38:27-30 (Perez and Zerah, Judah's sons by Tamar), and they will be important for the Davidic line (Matt 1:3). Twins create built-in ambiguity about birth-order precedence: which one is "firstborn" when both were conceived together? The womb-struggle (v22) already signaled the precedence-competition. In ANE law (various Mesopotamian legal texts), the firstborn who emerged first was the legal heir, regardless of which twin was conceived first — the narrative's careful recording of which came out first is therefore the legal question of inheritance rights.</p>""",
    "25": """<p>"The first to come out was red, and his whole body was like a hairy garment; so they named him Esau." The Hebrew wordplay: <em>ʾadmônî</em> (red/ruddy) anticipates <em>ʾĕḏôm</em> (Edom, the nation of Esau's descendants); the "hairy garment" (<em>kĕʾadderaṯ śēʿār</em>) connects to <em>śĕʿîr</em> (Seir, the mountain territory of Edom) and to <em>ʿēśāw</em> (Esau, perhaps related to the word for "hairy"). The triple wordplay — red/Edom, hairy/Seir, Esau — is built into the birth narrative: the man and his nation are described in a single pun. This kind of etiological name-play is standard in Genesis (Adam/ʾăḏāmāh, Eve/ḥāyāh, Cain/qānāh, Abel/heḇel, etc.), but Esau's naming packs three geographic/ethnic identifications into one description.</p>""",
    "26": """<p>"His brother came out, with his hand grasping Esau's heel; so he was named Jacob." The heel-grasping at birth is the etiological explanation for the name <em>yaʿăqōḇ</em> (Jacob) — from <em>ʿāqēḇ</em> (heel) via the verb <em>ʿāqaḇ</em> (to grab the heel, and by extension to supplant/deceive). Hosea 12:3 cites the heel-grasping: "in the womb he grasped his brother's heel." The same verb <em>ʿāqaḇ</em> appears in Esau's accusation in 27:36: "He has deceived me (<em>wayyaʿqĕḇēnî</em>) these two times — he took my birthright, and now he's taken my blessing." The heel-grabbing at birth is thus a character-signature: Jacob's entire life is a working-out of this birth-instinct. "Isaac was sixty years old when Rebekah gave birth" — the 20-year gap from marriage (v20) to birth confirms the extended barrenness.</p>""",
    "27": """<p>"Esau became a skillful hunter, a man of the open country, while Jacob was content to stay at home among the tents." The contrast is sharp in ANE social terms: the hunter (<em>ṣayāḏ</em>) lives in wild, uncultivated territory (<em>śāḏeh</em>, open field/country), while the tent-dweller (<em>yōšēḇ ʾohālîm</em>, one who sits/dwells in tents) represents the settled pastoral economy. Hunters in the ANE were associated with the pre-agricultural, wild-territory culture; tent-dwellers were the semi-settled pastoralists with flocks and herds. Nimrod is described as a "mighty hunter" (10:9) with a connotation of warrior-prowess; Esau's hunter identity connects him to this pre-covenant figure. The description of Jacob as <em>tām</em> (complete, blameless, simple — the same word used of Noah in 6:9 and Job in Job 1:1) qualifies his character before the deception narratives complicate it.</p>""",
    "28": """<p>"Isaac, who had a taste for wild game, loved Esau, but Rebekah loved Jacob." The parental favoritism is stated with candid directness. Isaac's love for Esau is given a physical reason (<em>kî-ṣayiḏ bĕpîw</em>, because game was in his mouth — his preference for Esau's wild game), while Rebekah's love for Jacob is stated without reason. The conditional character of Isaac's stated reason — his love depends on what Esau provides — is a subtle narrative commentary. In ANE patriarchal families, parental favoritism was not unusual, but the covenantal consequences of Isaac's preference for Esau (who despises his birthright) and Rebekah's for Jacob (who will carry the covenant) shape the entire deception narrative of ch27.</p>""",
    "29": """<p>"Once when Jacob was cooking some stew, Esau came in from the open country, famished." The scene is a classic ANE contrasting-brothers encounter: one working at domestic provision (cooking), the other returning empty from the hunt. The word <em>ʿāyēp</em> (famished/exhausted/weary) is the same word used for David's exhausted troops in 2 Sam 16:2; it implies genuine physical depletion but not mortal danger. The lentil stew (<em>nĕzîḏ ʿădāšîm</em>, cooked lentil dish) — lentils were a common staple food of the ancient Levant, the food of the poor and middle classes. The scene's irony is that the great hunter returns from the field unable to feed himself, while the tent-dweller has a pot of food ready.</p>""",
    "30": """<p>"Quick, let me have some of that red stew! I'm famished!" The Hebrew is vivid and colloquial: <em>halʿîṭēnî nāʾ min-hāʾāḏōm hāʾāḏōm hazzeh</em> (feed me, please, from that red, red [thing]) — the repetition of <em>ʾāḏōm</em> (red) twice, with the article <em>hazzeh</em> (this one), is emphatic and almost breathless. Esau cannot even name what he wants — he calls it "the red stuff" — a detail that highlights his fixation on immediate appetite over consideration. "That is why he was also called Edom" — the etiological comment: Edom (<em>ʾĕḏôm</em>, the nation of Esau's descendants) derives its name from Esau's craving for the red food. The Edomites as a people are named after their ancestor's moment of appetite-driven loss.</p>""",
    "31": """<p>"First sell me your birthright." Jacob's counter-demand is not spontaneous exploitation — it is a deliberate negotiation. The birthright (<em>bĕḵōrāh</em>) was the firstborn's legal right to a double portion of the inheritance (Deut 21:17) plus the family headship and, in this covenant family, the covenant-heir status. In ANE law (Nuzi texts from the 15th-14th century BCE document similar transactions among Hurrians), birthrights could be sold or transferred — they were legally tradeable property rights, not merely social customs. Jacob's "first" (<em>kāʿēt</em> — "sell me first" or "sell me right now") creates urgency: he is timing the offer to Esau's moment of maximum desperation.</p>""",
    "32": """<p>"Look, I am about to die. What good is the birthright to me?" Esau's argument is hyperbole in an ANE context: hunters knew hunger well; this one meal was not going to cause death. The word <em>hōlēk lāmût</em> (I am going to die) is the present participle of dying — "I am about to die," not "I am dying right now." The dismissal of the birthright as worthless under present circumstances is the narrative's key theological statement: Esau cannot see beyond his immediate physical need to the long-term covenantal value of what he holds. The author of Hebrews (12:16) will call Esau "godless" (<em>bébēlos</em>) for this exchange — not because he was immoral by other standards but because he treated the sacred (covenant-heir status) as profane (exchangeable for food).</p>""",
    "33": """<p>"But Jacob said, 'Swear to me first.' So he swore an oath to him, selling his birthright to Jacob." The sworn oath (<em>wĕyiššāḇaʿ lô</em>) is the legal formalization of the transaction. Oral contracts in the ANE were binding when accompanied by an oath sworn in the name of a deity. Jacob's insistence on the sworn oath converts what might have been a jesting exchange into a legally enforceable transfer. Nuzi texts from the ancient Near East (15th-century Hurrian legal documents) record actual cases where birthrights were traded for food and goods — the practice was apparently known and legally valid, though socially unusual. The oath-taking in Genesis is always serious: Abraham's servant swears (24:9), Jacob swears to Laban (31:53), Esau swears here.</p>""",
    "34": """<p>"Then Jacob gave Esau some bread and some lentil stew. He ate and drank, and then got up and left. So Esau despised his birthright." The narrator's five rapid verbs — ate, drank, got up, left, despised — deliver the verdict efficiently: the transaction was consummated with a meal (a form of covenant-ratification in ANE culture: eating together sealed agreements), and then Esau simply left. The final statement "So Esau despised (<em>wayyiḇez ʿēśāw</em>) his birthright" is the narrator's theological verdict — the verb <em>bāzāh</em> means to treat as contemptible/worthless (used for despising YHWH's word in 2 Sam 12:9-10; Mal 1:6). The birthright was not taken from Esau — he sold it willingly for a meal. The subsequent narrative (ch27) adds the stolen blessing, but the birthright was voluntarily transferred here.</p>"""
  },
  "26": {
    "1": """<p>"Now there was a famine in the land — besides the earlier famine in Abraham's time." The narrator distinguishes this famine from the one that sent Abraham to Egypt (12:10). The geographic destination is Gerar, ruled by "Abimelech king of the Philistines." The "Philistines" of Gerar in the patriarchal period are not the Sea Peoples Philistines of the Judges-Samuel period (who arrived ca. 1200 BCE from the Aegean); they are an earlier Aegean or coastal people group with a different historical profile. The title "Abimelech" (meaning "my father is king" or "Molech is father") appears to be a dynastic title — the same name appears in Abraham's generation (ch20-21) and now in Isaac's. The recurring Abimelech-Gerar connection creates a narrative parallel between Isaac and his father.</p>""",
    "2": """<p>"Do not go down to Egypt; live in the land where I tell you to live." The divine oracle interrupts what would have been Isaac's natural response to famine — repeating his father's journey to Egypt (12:10). YHWH's directive to stay in Canaan is the covenant-land imperative: the promise is tied to the land of Canaan, and leaving it (even for famine relief) jeopardizes the covenant's geographic dimension. Egypt represents the alternative to trust: material security but outside the covenant-territory. The "do not go down" (<em>ʾal-tēreḏ</em>) uses the same directional idiom as the later exodus-pattern: going "down" to Egypt (yāraḏ), coming "up" from Egypt (ʿālāh).</p>""",
    "3": """<p>"Stay in this land for a while, and I will be with you and will bless you." The covenant promise to Isaac parallels the promises to Abraham: presence (<em>ʾehyeh ʿimmāk</em>, I will be with you), blessing (<em>ʾăḇārekkā</em>), land, and descendants. "For to you and your descendants I will give all these lands" — the land-promise is addressed directly to Isaac for the first time (he heard it through Abraham before, but now it is renewed in his own theophany). "And will confirm the oath I swore to your father Abraham" — the covenant is not being re-initiated; it is being confirmed in continuity with Abraham. Isaac is the second link in a chain, not the start of a new covenant.</p>""",
    "4": """<p>"I will make your descendants as numerous as the stars in the sky." The star-analogy for Abraham's descendants (15:5; 22:17) is now repeated to Isaac — the same promise, the same scope. "And through your offspring all nations on earth will be blessed" — the all-nations blessing formula (12:3; 22:18) is restated to Isaac, confirming that the universal scope of the Abrahamic covenant passes through Isaac, not Ishmael or Keturah's sons. The word <em>wĕhitbārĕkû</em> (will bless themselves / will be blessed) — whether this is reflexive (nations will invoke Abraham's blessing on themselves) or passive (nations will be blessed through Abraham's offspring) is the question Paul addresses in Gal 3:8 — he reads it as a promise of Gentile inclusion.</p>""",
    "5": """<p>"Because Abraham obeyed me and kept my requirements, my commands, my decrees and my instructions." The four terms — <em>miśmerāt</em> (requirements/charges), <em>miṣwōt</em> (commandments), <em>ḥuqqōt</em> (decrees/statutes), <em>tôrōt</em> (instructions/laws) — are the precise vocabulary of the Mosaic law's categories (Lev 18:26; 20:22; Deut 11:1). The use of this law-vocabulary for Abraham's pre-Mosaic obedience is significant: the narrator is applying retrospective Mosaic categories to describe Abraham's covenant-faithfulness. Some interpreters understand this as evidence that Abraham received and kept an oral form of the law; others see it as the narrator's theological shorthand for Abraham's comprehensive covenant-loyalty. Either way, Isaac's inheritance of the covenant is grounded in his father's track record of faithfulness.</p>""",
    "6": """<p>"So Isaac stayed in Gerar." The brevity of this verse — one clause — is the narrative's way of marking Isaac's obedience to YHWH's directive without elaboration. He was told to stay (v2-5), and he stayed. The gēr-residence in Gerar is linguistically ironic: <em>gûr</em> (to sojourn as an alien) in <em>Gĕrār</em> (Gerar) — to sojourn in Sojourn-city. Gerar was a real city in the Negev (archaeological identifications vary between Tell Haror and other sites in the southwestern Canaan region), but its name in Hebrew echoes the patriarchs' theological identity as sojourners (<em>gĕrîm</em>) in a land not yet their own.</p>""",
    "7": """<p>"She is my sister, because he was afraid to say, 'She is my wife.'" Isaac's wife-sister deception is the third instance of this strategy in Genesis: Abraham used it with Pharaoh (12:11-13), Abraham used it with Abimelech of Gerar (20:2), and now Isaac uses it with Abimelech of Gerar. The repetition of the deception with the same city and same ruler-name has been read as a variant tradition of a single event, or as a literary type-scene demonstrating that the sons repeat the fathers' compromises. The stated reason — "they might kill me" — reflects real dangers: in ANE culture, killing the husband to take a beautiful wife was a recognized risk, though not necessarily common. Rebekah's beauty (v7) is the first attribute mentioned of her in her own story as Isaac's wife (she was described as beautiful in 24:16 during the servant's mission).</p>""",
    "8": """<p>"Abimelech king of the Philistines looked down from a window and saw Isaac caressing his wife Rebekah." The discovery mechanism is distinct from the earlier deceptions: Abraham was exposed by plagues (12:17) and by divine dream to Abimelech (20:3); Isaac is exposed by visible behavior. The verb <em>mĕṣaḥēq</em> (caressing/laughing/playing) is the Piel of <em>ṣāḥaq</em> (to laugh/play/caress) — the same root as Isaac's name (<em>yiṣḥāq</em>, he laughs). The word carries erotic overtones in this context (cf. 39:14,17 where Potiphar's wife uses the same verb for Joseph "playing with/caressing" her — a false accusation). The "window" (<em>ḥallôn</em>) is a palace architectural feature; the king's vantage from above confirms his social superiority.</p>""",
    "9": """<p>"'She is really your wife!' Why did you say, 'She is my sister'?" Abimelech's confrontation is direct and points out the moral problem: the deception put his subjects at risk of sexual transgression with another man's wife. Isaac's answer — "Because I thought I might lose my life on account of her" — is honest about his fear but does not address the moral dimension. The contrast with ch20 is notable: when Abraham did the same thing, YHWH intervened directly with a divine dream to stop any harm (20:3-7). Here no divine intervention occurs; the deception is exposed through the natural course of observation. Isaac must face the king's moral rebuke directly.</p>""",
    "10": """<p>"You would have brought guilt (<em>ʾāšam</em>) upon us." Abimelech's concern uses the technical term <em>ʾāšam</em> — the guilt-offering concept of inadvertent cultic/moral transgression that requires ritual atonement (Lev 5:14-19). The king is not merely expressing personal offense; he is articulating the ANE concept of collective ritual guilt: if one of his men had slept with a married woman unknowingly, the entire community would have incurred divine guilt requiring cleansing. The same concern appears in 20:9 when Abimelech confronts Abraham. The Philistine king's moral framework — shared guilt from unknowing transgression — reveals a developed sense of collective moral accountability that the narrative does not dismiss as pagan ignorance.</p>""",
    "11": """<p>"Anyone who harms this man or his wife shall certainly be put to death." Abimelech's royal decree provides Isaac and Rebekah with legal protection across his entire territory. This is a royal protection edict — a standard ANE royal prerogative: the king could extend his protection to individuals by public decree, making harm to them a capital offense. The same protection was extended to Abraham (20:7-8: Abimelech warned his entire household). The pagan king thus becomes the instrument of the covenant-family's protection — YHWH's providential use of Abimelech's authority to shield Isaac in the alien land.</p>""",
    "12": """<p>"Isaac planted crops in that land and the same year reaped a hundredfold, because the LORD blessed him." The hundredfold harvest (<em>mēʾāh šĕʿārîm</em>, a hundred measures) in the midst of a famine (v1) is an extraordinary sign: crop failures were the defining feature of a famine year; a hundredfold harvest was exceptional even in good years. Jesus will use the hundredfold harvest as the image of extraordinary covenant-fruitfulness in the Parable of the Sower (Matt 13:8,23), which suggests the hundredfold of Isaac was part of the cultural imagination of blessing. The explicit attribution — "the LORD blessed him" — prevents any misreading of the harvest as skill or luck.</p>""",
    "13": """<p>"The man became rich, and his wealth continued to grow until he became very wealthy." The threefold escalation — became rich (<em>wayyigdal</em>), grew (<em>wĕhālôk wĕgāḏēl</em>, kept going and growing), very wealthy (<em>gāḏôl mĕʾōḏ</em>, exceedingly great) — is the narrative's economic miracle report. The same escalating formula of prosperity is applied to Joseph in Egypt (39:2-3) and to Jacob in Laban's household (30:43). The accumulation of wealth by the covenant-bearer in a foreign land is a repeated narrative pattern: the covenant-blessing overflows its boundaries and prospers the carrier even in hostile territory.</p>""",
    "14": """<p>"He had so many flocks and herds and servants that the Philistines envied him." The Philistine envy echoes the later Egyptian envy of the multiplying Israelites (Exod 1:9-12: "the Israelites have become far too numerous for us"). The same social dynamic — a prospering foreign group threatening the host population's sense of security — runs from Isaac's sojourn through the Exodus and into the later biblical pattern of diaspora prosperity and host-community hostility. "Envied" (<em>wayyĕqannĕʾû</em>) is the same verb as Saul's envy of David (1 Sam 18:9) and Rachel's envy of Leah (30:1) — the covenant-man's prosperity generates dangerous resentment in those around him.</p>""",
    "15": """<p>"The Philistines had stopped up all the wells that Abraham's servants had dug, filling them with earth." Well-stopping was an act of territorial hostility and resource denial in the semi-arid Negev. Wells were among the most valuable resources in this landscape — without them, both humans and animals would die within days. Stopping wells with earth was a statement of ownership: "these wells are ours and you have no right to the water." The act also erased Abraham's territorial presence: his wells marked his claim to pastoral rights in the region; filling them removed the evidence of his occupation. This sets up Isaac's well-reopening narrative (vv18-22) as an act of covenant-persistence and territorial claim-reassertion.</p>""",
    "16": """<p>"Move away from us; you have become too powerful for us." Abimelech's expulsion of Isaac uses the same social dynamic that will appear in Exod 1:9 ("the Israelites have become too numerous and powerful for us"). The word <em>ʿāṣam</em> (to be powerful, numerous, mighty) is the same verb: "you have become too powerful" (<em>ʿāṣamtā mimmennû mĕʾōḏ</em>). Isaac's expulsion from Gerar despite Abimelech's earlier royal protection decree (v11) shows the limits of pagan hospitality toward a covenant-bearer whose prosperity outstrips the host culture's comfort. The expulsion, however, leads Isaac toward Beersheba and the renewed theophany (v24).</p>""",
    "17": """<p>"So Isaac moved away from there and encamped in the Valley of Gerar, where he settled." The move from the city of Gerar to the valley (<em>naḥal</em>, wadi/riverbed valley) is a geographic withdrawal that still keeps Isaac within the general Gerar region. He does not leave the territory entirely but occupies the less-contested pastoral zone — the valley areas were used for grazing and had seasonal water access. The wadi areas of the Negev had significant water potential even in arid conditions; digging in wadi beds was a standard water-access strategy (vv19-22). Isaac's settlement in the valley thus represents a pragmatic adaptation: forced from the city, he occupies the adjacent pastoral zone.</p>""",
    "18": """<p>"Isaac reopened the wells that had been dug in the time of his father Abraham." The well-reopening is an act of both territorial claim and covenant-continuity: by reopening Abraham's wells and giving them the same names his father had given them (<em>wayyiqrāʾ lāhem šēmôt kĕšēmōt ʾăšer-qārāʾ lāhem ʾāḇîw</em>), Isaac asserts both physical continuity (the same water sources) and name-continuity (the same wells, identifiable by the same names). In ANE culture, naming a well was an act of ownership-assertion; the names functioned as title-deeds. Isaac's restoration of Abraham's well-names is a covenant-inheritance act: he is claiming what his father established before him.</p>""",
    "19": """<p>"Isaac's servants dug in the valley and discovered a well of fresh water." <em>Mayim ḥayyîm</em> (living water / fresh water) — the phrase means running or spring water, as opposed to stored cistern water. Living water was the highest quality water in ANE Palestine: spring-fed, flowing, fresh, as opposed to collected rainfall or cistern water that could stagnate. The discovery of a living-water well in the wadi represents an exceptional find — these wells tap into underground springs rather than the water table. The same term will carry profound theological weight later: Jeremiah describes YHWH as "the spring of living water" (Jer 2:13; 17:13), and Jesus uses it in John 4:10-11 and 7:38.</p>""",
    "20": """<p>"The herders of Gerar quarreled with those of Isaac and said, 'The water is ours!'" The dispute over water rights was one of the most common sources of conflict in the semi-arid Levant — and one of the most serious, since water determined survival for both humans and flocks. The Gerar herdsmen's claim (<em>lānû hāmāyim</em>, "the water is ours") asserts territorial precedence. Isaac names the well "Esek" (<em>ʿēśeq</em>, dispute/strife — from <em>ʿāśaq</em>, to oppress, dispute). The naming of wells after the events surrounding their discovery is a standard Genesis pattern (16:14; 21:31; 26:33) — the well's name becomes a memorial of what happened there.</p>""",
    "21": """<p>"They dug another well, but they quarreled over that one too; so he named it Sitnah." <em>Sitnāh</em> means opposition/enmity — from the root <em>śāṭan</em> (adversary, the root of the name Satan). The naming of this second contested well "Adversary" is significant: the well is named after the adversarial force that prevents Isaac from resting. The sequence Esek (dispute) → Sitnah (adversary/opposition) → Rehoboth (spaciousness) charts a three-stage conflict-to-resolution arc: two rounds of contest, then withdrawal to a place where no one contests. The pattern mirrors Israel's later wilderness conflicts before entering Canaan: multiple confrontations before finding space.</p>""",
    "22": """<p>"He moved on from there and dug another well, and no one quarreled over it. He named it Rehoboth, saying, 'Now the LORD has given us room (<em>hirḥîḇ</em>) and we will flourish in the land.'" <em>Rĕḥōḇôt</em> (spaciousness, broad places — from <em>rāḥaḇ</em>, to be wide, spacious) is the name Isaac gives to the uncontested well. The verbal root <em>rāḥaḇ</em> is used for the widening of covenantal scope: "enlarge the place of your tent" (Isa 54:2); the broad place of divine deliverance (Ps 18:19; 31:8). Isaac's declaration — "now the LORD has given us room" — interprets the uncontested well as a divine gift: not just a physical well, but the space to flourish. "We will flourish in the land" (<em>wĕpārînû bāʾāreṣ</em>, we will be fruitful in the land) uses the creation-blessing verb <em>pārāh</em> (to be fruitful) from Gen 1:28.</p>""",
    "23": """<p>"From there he went up to Beersheba." The move from the Valley of Gerar to Beersheba is a northward journey into the Negev highlands. Beersheba is Abraham's covenantal site: where he planted a tamarisk tree (21:33), called on YHWH's name as El Olam, and made his covenant with Abimelech (21:31-32). Isaac's arrival at Beersheba connects him to his father's covenant-activity at the same location. Beersheba will also be Jacob's departure point for Egypt (46:1-5), making it the covenant-family's southern threshold — the last Canaanite city before the Negev wilderness. The move "up" (<em>wayyaʿal</em>) to Beersheba may also have theological significance: ascending to a covenant-sacred site.</p>""",
    "24": """<p>"That night the LORD appeared to him and said, 'I am the God of your father Abraham. Do not be afraid, for I am with you; I will bless you.'" The nighttime theophany at Beersheba uses the same <em>ʾal-tîrāʾ</em> (do not be afraid) covenant-reassurance formula that appears at all major covenant-renewal encounters (15:1 to Abraham; 26:24 here; 46:3 to Jacob). The divine self-identification as "the God of your father Abraham" grounds the theophany in covenant-continuity: Isaac is being addressed as Abraham's heir, not as a new covenant-partner starting from scratch. "For the sake of my servant Abraham" (<em>baʿăḇûr ʾaḇrāhām ʿaḇdî</em>) — the servant-title is significant: Abraham's covenant-relationship with YHWH was that of a <em>ʿeḇeḏ</em> (servant/slave), the highest honor in the ANE patron-servant framework.</p>""",
    "25": """<p>"Isaac built an altar there and called on the name of the LORD. There he pitched his tent, and there his servants dug a well." The three-fold response to the theophany — altar-building, tent-pitching, well-digging — mirrors Abraham's pattern at every major theophanic site (12:7-8: altar + tent; 13:18: altar; 21:33: tamarisk + calling on the name). The altar-building (<em>wayyiḇen šām mizḇēaḥ</em>) at a theophanic site is the patriarchal way of consecrating a location — making it a worship-site and covenant-marker. "Called on the name of the LORD" is the prayer-formula of the patriarchs (12:8; 13:4; 21:33) — invoking YHWH's presence at the altar. The well-digging at Beersheba reasserts the earlier well-rights at this site (21:25-32).</p>""",
    "26": """<p>"Meanwhile, Abimelech had come to him from Gerar, with Ahuzzath his personal adviser and Phicol the commander of his forces." The appearance of Abimelech with his adviser (or "friend," <em>mēreʿēhû</em>) and military commander parallels the Abraham-Abimelech covenant scene (21:22: "Abimelech and Phicol the commander of his forces came to Abraham"). The same Phicol appears across the generation — either a very long-lived individual, a dynastic title, or a literary paralleling of the two scenes. The appearance of the Philistine king and his chief military officer signals that this is a treaty-level encounter: the king himself comes with his treaty-signing delegation.</p>""",
    "27": """<p>"Why have you come to me, since you were hostile to me and sent me away?" Isaac's challenge uses the honorable-confrontation rhetorical form: state the grievance before receiving the visitor's proposal. "Hostile to me" (<em>śĕnēʾtem ʾōtî</em>, you hated me) — the word <em>śānēʾ</em> (to hate) in a treaty context means to treat as an enemy rather than a covenant-ally. Expelling someone from your territory is an act of hostility in ANE custom, regardless of the polite terms used. Isaac is right to name the contradiction: they sent him away, and now they have come to him. The social protocol required acknowledging this dissonance before a new covenant could be established.</p>""",
    "28": """<p>"We saw clearly that the LORD was with you." The verb <em>rāʾôh rāʾînû</em> (we saw, we saw — the infinitive absolute construction for emphasis: "we certainly saw / we clearly saw") is the covenant-witness formula. Abimelech's acknowledgment that YHWH is with Isaac is the pagan king's testimony to the visible effects of the covenant-blessing: a hundredfold harvest in a famine year, growing wealth that the Philistines themselves could not match, and prosperity that followed Isaac even into the valley. The treaty proposal — "let there be a sworn agreement (<em>ʾālāh</em>, oath/curse) between us" — follows the ANE treaty pattern: witnessed recognition of the superior party's divine backing, followed by a formal covenant.</p>""",
    "29": """<p>"That you will do us no harm, just as we did not harm you but always treated you well and sent you away in peace. And now you are the blessed of the LORD." Abimelech's proposed treaty terms revise history diplomatically: "we did not harm you" reframes the expulsion (v16) as benign management rather than hostile expulsion, and "sent you away in peace" puts a positive gloss on what was clearly a coercive departure. The phrase "the blessed of the LORD" (<em>ʾattāh ʿattāh bĕrûk YHWH</em>) is Abimelech's acknowledgment of Isaac's covenant-status — a remarkable admission from a pagan king: the man I expelled is YHWH's blessed one, and I now want to be in covenant with him. The same formula appears when Laban acknowledges that YHWH has blessed him through Jacob (30:27).</p>""",
    "30": """<p>"Isaac then made a feast for them, and they ate and drank." The covenant-ratification meal is the standard ANE treaty-sealing ceremony: shared food and drink in the presence of witnesses transforms a verbal agreement into a binding covenant. The sequence — verbal agreement (vv28-29), then feast, then oath-taking (v31) — is the standard treaty format in both Mesopotamian and Levantine diplomacy. The Sinai covenant follows a similar pattern: covenant terms, then the covenant meal on the mountain (Exod 24:11: "they saw God, and they ate and drank"). The meal creates a bond between parties that is more than a contract — it is a shared-life commitment sealed by shared table.</p>""",
    "31": """<p>"Early the next morning the men swore an oath to each other." The oath-taking after the meal is the treaty's formal legal seal. "Early in the morning" (<em>baббōqer</em>) is the standard time for solemn covenant-ceremonies (cf. 28:18: Jacob rises early to set up his pillar; Exod 24:4: Moses rises early for the Sinai covenant-ceremony). The mutual oath (<em>wĕyiššāḇĕʿû ʾîš lĕʾāḥîw</em>, each man swore to his brother) is bilateral: Isaac swears to Abimelech and Abimelech swears to Isaac. "They went away peacefully" — the covenant established a legal framework for coexistence that removes the ongoing conflict dynamic of the wells and the expulsion. The narrative closes the Gerar-conflict episode with formal peace.</p>""",
    "32": """<p>"That day Isaac's servants came and told him about the well they had dug. They said, 'We've found water!'" The timing — same day as the covenant-ceremony — is the narrative's providential marker: on the day Isaac establishes peace with Abimelech, his servants find water at Beersheba. The coincidence of treaty-day and water-discovery is presented without explicit commentary; the narrator trusts the reader to see the connection: covenant-making brings blessing, and the blessing appears immediately. The well-finding at Beersheba is both practical provision and a covenant-sign, connecting the water of physical survival to the covenant-water of YHWH's presence.</p>""",
    "33": """<p>"He called the well Shibah (<em>šiḇʿāh</em>, or <em>šĕḇūʿāh</em>), and to this day the name of the town has been Beersheba." The name Beersheba has a double etymology: in 21:31 it was "Beersheba" because Abraham and Abimelech "swore" (<em>nišbĕʿû</em>) there, and because of the "seven (<em>šeḇa</em>) lambs" used in the covenant. Here the well name "Shibah" derives from <em>šāḇaʿ</em> (to swear) — the oath-connection again. The town name Beersheba thus carries a layered etymology: well-of-the-oath (from the swearing), well-of-seven (from the seven lambs of Abraham's treaty). The "to this day" formula (<em>ʿad hayyôm hazzeh</em>) grounds the story in the reader's experience — Beersheba was a known and important city in later Israelite history (the southern boundary of Israel: "from Dan to Beersheba").</p>""",
    "34": """<p>"When Esau was forty years old, he married Judith daughter of Beeri the Hittite, and also Basemath daughter of Elon the Hittite." Esau's marriage at 40 creates a deliberate parallel and contrast with Isaac's marriage at 40 (v20): Isaac married Rebekah from within the covenant-family in Paddan Aram; Esau at the same age marries two Hittite women from Canaan. The Hittites are the local Canaanite population (not the imperial Hittites of Anatolia, but the Heth-descended Canaanites of Gen 10:15). The double marriage to Canaanite women contravenes the covenant-family pattern: Abraham explicitly prohibited Isaac from marrying Canaanites (24:3). Esau's choice is another instance of his disregard for covenant-heritage priorities — following the birthright sale (vv32-34) and preceding the stolen blessing (ch27).</p>""",
    "35": """<p>"They were a source of grief (<em>mōrat rûaḥ</em>, bitterness of spirit) to Isaac and Rebekah." The phrase <em>mōrat rûaḥ</em> literally means "bitterness of spirit" — the wives caused spiritual/emotional anguish to the in-laws. This verse is the setup for 27:46 and 28:1: Rebekah's stated reason for sending Jacob to Paddan Aram is fear that he will also marry Hittite women ("I'm disgusted with living because of these Hittite women"). The two-verse closing of ch26 thus serves as a narrative bridge: Esau's Canaanite marriages create the family crisis that motivates the next major narrative development — Jacob's journey to Paddan Aram, where he will find his wives within the covenant-family, receive the covenant blessing from YHWH, and become Israel.</p>"""
  }
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_CONTEXT)
    save_comm('mkt-context', 'genesis', existing)

    result = load_comm('mkt-context', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [25, 26]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    print(f'  Genesis context total: {len(result)} chapters, {after_count} verses')
    print('Genesis 25–26 mkt-context written.')

if __name__ == '__main__':
    main()
